// V1.0: 准备同步参数 — 获取上次同步时间
const companyCode = $env.DP_COMPANY_CODE;
if (!companyCode) {
  return { json: { _error: true, message: 'DP_COMPANY_CODE 未配置' } };
}

// 默认同步最近90天数据
const now = new Date();
const defaultFrom = new Date(now.getTime() - 90 * 86400000);
const dateFrom = defaultFrom.toISOString().split('T')[0];

return { json: {
  _error: false,
  company_code: companyCode,
  date_from: dateFrom,
  doc_types: ['SO', 'PO', 'WO', 'TR']
} };

// V3.1: 准备同步日期+时间 (空表=全量, 有数据=增量)
const params = $('准备参数').first().json;
const lastSync = $input.first().json.last_sync_date;
const lastSyncTime = $input.first().json.last_sync_time || '00:00:00';

// 空表: 返回 full_sync 标志, 不带日期条件
if (!lastSync) {
  // 全量同步限制最近 90 天，避免数据量过大导致 OOM
  const d = new Date();
  d.setDate(d.getDate() - 90);
  const limitDate = d.toISOString().slice(0, 10);
  return { json: {
    last_sync_date: limitDate,
    last_sync_ts_int: 0,
    full_sync: false,
    company_code: params.company_code
  } };
}

// 有数据: 增量同步
if (!/^\d{4}-\d{2}-\d{2}$/.test(lastSync)) {
  return { json: { _error: true, message: `同步日期格式异常: ${lastSync}` } };
}

// SAP UpdateTS 是整数格式 (HHMMSS, 如 153045), 将 HH:MM:SS 转回整数
const timeParts = lastSyncTime.split(':');
const lastSyncTsInt = parseInt((timeParts[0] || '00') + (timeParts[1] || '00') + (timeParts[2] || '00'), 10) || 0;

return { json: {
  last_sync_date: lastSync,
  last_sync_ts_int: lastSyncTsInt,
  full_sync: false,
  company_code: params.company_code
} };

// V3.3: 转换SAP数据 → OMS UPSERT SQL (含 WO BOM 抬头字段)
// 安全: esc() 转义字符串, num() 校验数值, 防 SQL 注入
const rows = $input.all().map(r => r.json);
const companyCode = $env.DP_COMPANY_CODE;

// 过滤无效行 (alwaysOutputData=true 时 SAP 返回 0 行会产生空 item)
const validRows = rows.filter(r => r.doc_type && r.sap_doc_entry);
if (!validRows || validRows.length === 0) {
  return { json: { skip: true, count: 0, message: 'OMS: 无 SAP 数据需要同步' } };
}

// 按 doc_type + sap_doc_entry 分组为订单头
const orderMap = new Map();
validRows.forEach(r => {
  const key = `${r.doc_type}_${r.sap_doc_entry}`;
  if (!orderMap.has(key)) {
    orderMap.set(key, {
      doc_type: r.doc_type,
      sap_doc_entry: r.sap_doc_entry,
      sap_doc_num: String(r.sap_doc_num),
      business_partner: r.business_partner || '',
      bp_name: r.bp_name || '',
      doc_date: r.doc_date || null,
      due_date: r.due_date || null,
      sap_status: r.sap_status || 'O',
      sap_cancelled: r.sap_cancelled || 'N',
      doc_total: r.doc_total || 0,
      doc_currency: r.doc_currency || '',
      sap_update_date: r.sap_update_date || null,
      sap_update_time: r.sap_update_time || '00:00:00',
      header_item_code: r.header_item_code || null,
      header_item_name: r.header_item_name || null,
      header_planned_qty: r.header_planned_qty != null ? r.header_planned_qty : null,
      header_actual_qty: r.header_actual_qty != null ? r.header_actual_qty : null,
      header_warehouse: r.header_warehouse || null,
      lines: []
    });
  }
  orderMap.get(key).lines.push({
    line_num: r.line_num,
    item_code: r.item_code || '',
    item_name: r.item_name || '',
    quantity: r.quantity || 0,
    open_quantity: r.open_quantity || 0,
    warehouse_code: r.warehouse_code || '',
    uom: r.uom || '',
    ship_date: r.ship_date || null
  });
});

// 安全: 字符串转义 + 数值校验
const esc = (v) => String(v || '').replace(/'/g, "''");
const num = (v) => { const n = Number(v); return isNaN(n) ? 0 : n; };
const escOrNull = (v) => v === null || v === undefined ? 'NULL' : `'${esc(v)}'`;
const numOrNull = (v) => v === null || v === undefined ? 'NULL' : num(v);
const orders = Array.from(orderMap.values());

// 生成批量 SQL
const batches = [];
const batchSize = 100;

for (let i = 0; i < orders.length; i += batchSize) {
  const batch = orders.slice(i, i + batchSize);
  let sql = '';

  batch.forEach(o => {
    // 计算 sap_data_hash (MD5 of key fields)
    const hashInput = `${o.sap_status}|${o.sap_cancelled}|${o.doc_total}|${o.business_partner}|${o.lines.length}|${o.header_item_code || ''}|${o.header_planned_qty != null ? o.header_planned_qty : ''}|${o.header_actual_qty != null ? o.header_actual_qty : ''}`;

    // doc_number = sap_doc_num
    sql += `
      INSERT INTO oms.orders (company_code, doc_type, doc_number, sap_doc_entry, sap_doc_num,
        business_partner, bp_name, doc_date, due_date, sap_status, sap_cancelled,
        doc_total, doc_currency, sap_update_date, sap_update_time,
        item_code, item_name, planned_qty, actual_qty, warehouse_code,
        sap_data_hash, sap_last_seen_at, oms_status)
      VALUES ('${esc(companyCode)}', '${esc(o.doc_type)}', '${esc(o.sap_doc_num)}', ${num(o.sap_doc_entry)}, '${esc(o.sap_doc_num)}',
        '${esc(o.business_partner)}', '${esc(o.bp_name)}', ${escOrNull(o.doc_date)}, ${escOrNull(o.due_date)},
        '${esc(o.sap_status)}', '${esc(o.sap_cancelled)}',
        ${num(o.doc_total)}, '${esc(o.doc_currency)}', ${escOrNull(o.sap_update_date)}, ${escOrNull(o.sap_update_time)},
        ${escOrNull(o.header_item_code)}, ${escOrNull(o.header_item_name)},
        ${numOrNull(o.header_planned_qty)}, ${numOrNull(o.header_actual_qty)},
        ${escOrNull(o.header_warehouse)},
        MD5('${esc(hashInput)}'), NOW(), 'pending')
      ON CONFLICT (company_code, doc_type, sap_doc_entry) WHERE parent_id IS NULL AND sap_doc_entry IS NOT NULL
      DO UPDATE SET
        doc_number = EXCLUDED.doc_number,
        sap_doc_num = EXCLUDED.sap_doc_num,
        business_partner = EXCLUDED.business_partner, bp_name = EXCLUDED.bp_name,
        doc_date = EXCLUDED.doc_date, due_date = EXCLUDED.due_date,
        sap_status = EXCLUDED.sap_status, sap_cancelled = EXCLUDED.sap_cancelled,
        doc_total = EXCLUDED.doc_total, doc_currency = EXCLUDED.doc_currency,
        sap_update_date = EXCLUDED.sap_update_date, sap_update_time = EXCLUDED.sap_update_time,
        item_code = EXCLUDED.item_code, item_name = EXCLUDED.item_name,
        planned_qty = EXCLUDED.planned_qty, actual_qty = EXCLUDED.actual_qty,
        warehouse_code = COALESCE(EXCLUDED.warehouse_code, oms.orders.warehouse_code),
        sap_data_hash = EXCLUDED.sap_data_hash, sap_last_seen_at = NOW(),
        oms_status = CASE
          WHEN oms.orders.oms_status IN ('split', 'executing') THEN oms.orders.oms_status
          WHEN EXCLUDED.sap_cancelled = 'Y' THEN 'cancelled'
          WHEN EXCLUDED.sap_status IN ('C', 'L') THEN 'completed'
          ELSE oms.orders.oms_status
        END,
        execution_state = CASE
          WHEN oms.orders.oms_status IN ('split') OR oms.orders.execution_state = 'executing' THEN oms.orders.execution_state
          WHEN EXCLUDED.sap_cancelled = 'Y' THEN 'done'
          WHEN EXCLUDED.sap_status IN ('C', 'L') THEN 'done'
          ELSE oms.orders.execution_state
        END
;
    `;

    // 行项目 UPSERT
    o.lines.forEach(ln => {
      sql += `
        INSERT INTO oms.order_lines (order_id, line_num, item_code, item_name,
          quantity, open_quantity, warehouse_code, uom, ship_date)
        SELECT id, ${num(ln.line_num)}, '${esc(ln.item_code)}', '${esc(ln.item_name)}',
          ${num(ln.quantity)}, ${num(ln.open_quantity)}, '${esc(ln.warehouse_code)}', '${esc(ln.uom)}',
          ${escOrNull(ln.ship_date)}
        FROM oms.orders
        WHERE company_code = '${esc(companyCode)}' AND doc_type = '${esc(o.doc_type)}'
          AND sap_doc_entry = ${num(o.sap_doc_entry)} AND parent_id IS NULL
        ON CONFLICT (order_id, line_num)
        DO UPDATE SET
          item_code = EXCLUDED.item_code, item_name = EXCLUDED.item_name,
          quantity = EXCLUDED.quantity, open_quantity = EXCLUDED.open_quantity,
          warehouse_code = EXCLUDED.warehouse_code, uom = EXCLUDED.uom,
          ship_date = EXCLUDED.ship_date;
      `;
    });
  });

  batches.push({ json: { sql, batch_num: Math.floor(i/batchSize) + 1, order_count: batch.length } });
}

return batches.length > 0 ? batches : [{ json: { skip: true, count: 0 } }];

// V1.1: 汇总同步结果 — 从生成节点获取 order_count (修复 PG 节点丢失字段)
const allItems = $('生成UPSERT SQL').all();
let totalOrders = 0;

allItems.forEach(item => {
  totalOrders += (item.json.order_count || 0);
});

return { json: {
  success: true,
  count: totalOrders,
  message: 'OMS 订单同步完成: ' + totalOrders + ' 个订单已处理'
} };
